import GridItem from "./GridItem";

export default function Grid({ items, selectedId, onSelect }) {
  return (
    <div
      style={{
        display: "grid",
        gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
        justifyItems: "center",
        gap: "16px",
        width: "100%",
      }}
    >
      {items.map((item) => (
        <GridItem
          key={item.id}
          item={item}
          selectedId={selectedId}
          changeSelected={onSelect}
        />
      ))}
    </div>
  );
}
